type filterActionOption struct {
	value string
	label string
}

func filterActionOptions() []filterActionOption {
	return []filterActionOption{
		{models.FilterActionArchive, "Archive"},
		{models.FilterActionDelete, "Delete"},
		{models.FilterActionMarkRead, "Mark as Read"},
		{models.FilterActionStar, "Star"},
		{models.FilterActionQuarantine, "Quarantine"},
	}
}

func filterActionBadgeClass(action string) string {
	switch action {
	case models.FilterActionArchive:
		return "bg-blue-100 text-blue-700"
	case models.FilterActionDelete:
		return "bg-red-100 text-red-700"
	case models.FilterActionMarkRead:
		return "bg-green-100 text-green-700"
	case models.FilterActionStar:
		return "bg-yellow-100 text-yellow-700"
	case models.FilterActionQuarantine:
		return "bg-orange-100 text-orange-700"
	default:
		return "bg-gray-100 text-gray-600"
	}
}

func filterConditionsSummary(rule *models.FilterRule) string {
	if len(rule.Conditions) == 0 {
		return "No conditions"
	}
	joiner := " AND "
	if !rule.MatchAll {
		joiner = " OR "
	}
	parts := make([]string, 0, len(rule.Conditions))
	for _, c := range rule.Conditions {
		val := ""
		if c.Value != nil {
			val = " \"" + *c.Value + "\""
		}
		parts = append(parts, c.Field+" "+c.Operator+val)
	}
	result := ""
	for i, p := range parts {
		if i > 0 {
			result += joiner
		}
		result += p
	}
	return result
}

func filterFormData(rule *models.FilterRule) string {
	type condData struct {
		Field    string `json:"field"`
		Operator string `json:"operator"`
		Value    string `json:"value"`
	}
	methods := `, addCondition() { this.conditions.push({ field: 'from', operator: 'contains', value: '' }); }, removeCondition(i) { this.conditions.splice(i, 1); } }`
	if rule == nil {
		return `{ conditions: [{ field: 'from', operator: 'contains', value: '' }]` + methods
	}
	conds := make([]condData, 0, len(rule.Conditions))
	for _, c := range rule.Conditions {
		val := ""
		if c.Value != nil {
			val = *c.Value
		}
		conds = append(conds, condData{Field: c.Field, Operator: c.Operator, Value: val})
	}
	b, err := json.Marshal(conds)
	if err != nil {
		b = []byte("[]")
	}
	return fmt.Sprintf(`{ conditions: %s%s`, b, methods)
}

